parameters.query:
SELECT *
FROM caify_prompt
  where member_pk = {{ $json.member_pk }}
LIMIT 1;

parameters.jsCode:
// n8n Code node (Run Once for All Items)

const map_service_types = {
  1: '오프라인 매장',
  2: '온라인 서비스',
  3: '전국 서비스',
  4: '프랜차이즈',
  5: '기타',
};

const map_ages = {
  1: '10대',
  2: '20대',
  3: '30대',
  4: '40대',
  5: '50대',
};

const map_strengths = {
  1: '가격이 합리적이다.',
  2: '결과·성과가 명확하다.',
  3: '전문 인력이 직접 제공한다.',
  4: '처리 속도가 빠르다.',
  5: '경험·사례가 많다.',
  6: '접근성이 좋다.',
  7: '사후 관리가 잘 된다.',
  8: '공식 인증·자격을 보유하고 있다.',
  9: '기술력이 높다.',
  10: '기타',
};

const map_tones = {
  1: '차분하게 설명한다.',
  2: '친절하게 쉽게 설명한다.',
  3: '단호하고 확신 있게 말한다.',
  4: '전문가가 조언하는 느낌.',
};

const map_goal = {
  1: '매출을 늘리고 싶다',
  2: '예약·방문을 늘리고 싶다.',
  3: '문의·상담을 늘리고 싶다.',
  4: '브랜드를 알리고 싶다.',
  5: '신뢰를 확보하고 싶다.',
  6: '기타',
};

const map_keep_style = {
  1: '유지한다.',
  2: '유지하지 않는다.',
};

const map_content_styles = {
  1: '짧은 문장 위주',
  2: '핵심 요약',
  3: '질문으로 마무리',
  4: '숫자·근거 강조',
};

const map_action_style = {
  1: '정보만 제공하고 판단은 맡긴다.',
  2: '관심이 생기도록 자연스럽게 유도한다.',
  3: '지금 바로 행동하도록 안내한다.',
};

const map_expression = {
  1: '과장된 표현',
  2: '가격·할인 언급',
  3: '타사 비교·비방 표현',
  4: '기타',
};

// ✅ 추가: postLengthModeRaw 변환
const map_postLengthMode = {
  1: '요약형',
  2: '설명형',
  3: '전문가',
};

function join(arr, map) {
  if (!Array.isArray(arr)) return '';
  const result = [];
  for (const n of arr) {
    const key = Number(n);
    if (map[key]) result.push(map[key]);
  }
  return result.join(' / ');
}

function one(value, map) {
  const key = Number(value ?? 0);
  return map[key] ?? '';
}

const items = $input.all();

return items.map((item) => {
  const row = item.json;

  const payload = {
    ok: true,
    id: row.id ?? null,
    member_pk: row.member_pk ?? null,
    brand_name: row.brand_name ?? '',
    product_name: row.product_name ?? '',
    industry: row.industry ?? '',
    inquiry_channels: row.inquiry_channels ?? '',

    service_types: join(row.service_types, map_service_types),
    address: `${row.address1 ?? ''} ${row.address2 ?? ''}`.trim(),
    address_zip: row.address_zip ?? '',
    goal: one(row.goal, map_goal),
    ages: join(row.ages, map_ages),
    product_strengths: join(row.product_strengths, map_strengths),
    tones: join(row.tones, map_tones),

    // ✅ 원본 유지
    postLengthModeRaw: row.postLengthModeRaw ?? null,
    // ✅ 변환 값 추가
    postLengthMode: one(row.postLengthModeRaw, map_postLengthMode),

    keep_style: one(row.keep_style, map_keep_style),
    style_url: row.style_url ?? '',
    content_styles: join(row.content_styles, map_content_styles),
    extra_strength: row.extra_strength ?? '',
    action_style: one(row.action_style, map_action_style),

    expression: one(Array.isArray(row.expressions) ? row.expressions[0] : null, map_expression),

    forbidden_phrases: row.forbidden_phrases ?? '',
    content_styles_raw: row.content_styles ?? null,
    expressions_raw: row.expressions ?? null,
    member_intro : row.intro ?? null,
    member_outtro : row.outtro ?? null,
  };

  return { json: payload };
});

const industryMap = {
  "동물": "animal_hospital",
  "세무": "tax_accounting",
  "카페": "cafe",
  "법무법인": "law_firm",
  "법인": "corp_consulting",
  "경영컨설팅": "corp_consulting",
  "골프": "golf",
  "안전관리": "safety",
  "펜션" : "lodging_pension",
  "교육" : "academy",
  "뷰티" : "beauty"
};

const industryCode = industryMap[$json.industry] || "unknown";

// 고객 고유 키
const companyKey = `m${$json.member_pk}`;

// 업종 공통 풀 키
const poolKey = `${industryCode.split('_')[0]}_default`;

return {
  ...$json,
  industryCode,
  companyKey,
  poolKey
};

// Node: Build Query Context (Code)
const norm = (s) => String(s ?? "").replace(/\s+/g, " ").trim();

const productName = norm($json.product_name);
const extraStrength = norm($json.extra_strength);

const productTokens = productName
  .split(/[,\n/]/g).map(norm).filter(Boolean); // ["애견 미용", "슬개골탈구 수술"]

const extraTokens = extraStrength
  .split(/[,\n/]/g).map(norm).filter(Boolean); // ["슬개골탈구 수술 경력 100회", "넓고 쾌적한 매장"]

return {
  json: {
    ...$json,
    productTokens,
    extraTokens,
    lookbackDays: 14,
    // role별 최종 후보 개수
    pickPlan: { promo: 3, info: 3, plusA: 4 },
    // role별 “가져올” 후보 개수 (넉넉히)
    fetchPlan: { promo: 20, info: 20, plusA: 30 }
  }
};

const ctx = $items("가중치부여1")[0].json;

return $input.all().map(item => ({
  json: {
    ...item.json,   // ✅ 후보 1개
    ctx            // ✅ 가중치부여 통째로 첨부(네임스페이스)
  }
}));

//------------------------------------------------
// BLOG_PROMPT_BUILDER_V10_LIGHT
// 핵심 변경
// 1) 기존 V8 구조 최대한 유지
// 2) 업종 불문 범용을 위해 offering_type / cta_mode만 최소 추가
// 3) questionStrategy 같은 사전 설계 제거
// 4) role은 강조 강도만 조절하고, 질문/H2 구조는 LLM이 판단하게 둔다
// 5) tone/actionStyle/expression을 _meta로 승격해 후속 노드에서 보존 가능하게 함
//------------------------------------------------

function safeObj(x){
  return x && typeof x === "object" && !Array.isArray(x) ? x : {};
}

function safeArr(x){
  return Array.isArray(x) ? x : [];
}

function norm(s){
  return String(s ?? "").replace(/\s+/g, " ").trim();
}

function safeItems(nodeName){
  try{
    return $items(nodeName) || [];
  }catch{
    return [];
  }
}

//------------------------------------------------
// input + ctx
//------------------------------------------------
const inJson = safeObj($json);

const ctxItem = safeItems("가중치부여1")[0];
const externalCtx = ctxItem?.json ? safeObj(ctxItem.json) : {};

const ctx = safeObj(
  inJson.ctx && Object.keys(safeObj(inJson.ctx)).length
    ? inJson.ctx
    : externalCtx
);

//------------------------------------------------
// keyword input compat
//------------------------------------------------
const keywordCandidates10 =
  safeArr(inJson.keywordCandidates10).length
    ? safeArr(inJson.keywordCandidates10)
    : safeArr(inJson.keywordCandidates);

const keywordCandidates3 =
  safeArr(inJson.keywordCandidates3).length
    ? safeArr(inJson.keywordCandidates3)
    : keywordCandidates10.slice(0, 3);

//------------------------------------------------
// main keyword
//------------------------------------------------
const selectedKeywords = (() => {
  const k0 = keywordCandidates3[0] || keywordCandidates10[0];

  const main =
    norm(k0?.keyword_norm ?? k0?.keyword) ||
    norm(ctx.keywordDisplay) ||
    norm(safeArr(ctx.productTokens)[0]) ||
    "";

  return main ? [main] : [];
})();

const mainKeyword = selectedKeywords[0] || "";

//------------------------------------------------
// mode
//------------------------------------------------
const raw = Number(ctx.postLengthModeRaw ?? 0);

function resolveMode(v){
  if (v === 1) return "summary";
  if (v === 2) return "explain";
  if (v === 3) return "expert";
  return "summary";
}

const mode = resolveMode(raw);

//------------------------------------------------
// role
//------------------------------------------------
const postRoleRaw = norm(
  keywordCandidates3[0]?.role ??
  keywordCandidates10[0]?.role ??
  inJson.role ??
  ctx.role ??
  ""
).toLowerCase();

function resolveRole(r){
  if (r === "info") return "info";
  if (r === "promo") return "promo";
  if (r === "plusa") return "plusA";
  return "promo";
}

const postRole = resolveRole(postRoleRaw);

//------------------------------------------------
// role guide
//------------------------------------------------
const commonRoleBase = `
공통 원칙
- 모든 글은 정보성 기반으로 작성한다
- 모든 글은 독자의 흥미를 끄는 요소를 반드시 포함한다
- 모든 글은 브랜드 또는 서비스/상품이 자연스럽게 최소 1회 이상 등장해야 한다
- 단, 브랜드를 독립 소개 문단처럼 따로 꺼내지 않는다
- 브랜드는 판단 기준, 확인 포인트, 차이 설명, 이용 맥락 안에서만 자연스럽게 반영한다
- 직접적인 광고 문장, 과장 문장, 노골적인 전환 유도 문장은 금지한다
- 읽고 나면 "도움이 될 만한 선택지나 제공 주체가 있겠구나" 정도의 인식은 남아야 한다
`;

const roleGuideMap = {
  promo: `
promo
${commonRoleBase}
- 세 role 중 정보 밀도와 판단 기준이 가장 또렷해야 한다
- 브랜드/서비스/상품은 정보 설명의 일부처럼 자연스럽게 녹여 쓴다
- 전환을 밀기보다 주제 이해와 실수 방지가 먼저 남아야 한다
`,
  info: `
info
${commonRoleBase}
- 세 role 중 브랜드/서비스/상품의 존재감이 가장 또렷해야 한다
- 정보만 주고 끝내지 말고, 왜 한 번 더 비교해볼 만한지와 어떤 도움을 받을 수 있는지가 자연스럽게 남아야 한다
- 독자가 읽고 나면 "이건 그냥 넘기지 말고 한 번 더 따져봐야겠다"는 생각이 남아야 한다
- 단, 홍보 문장이 따로 튀지 않게 하고 정보 흐름 안에서만 설득한다
`,
  plusA: `
plusA
${commonRoleBase}
- 세 role 중 문제 제기와 흥미 유도가 가장 또렷해야 한다
- 검색자가 실제로 막히는 지점, 오해하는 지점, 그냥 넘기기 쉬운 지점을 앞쪽에서 분명히 건드린다
- 해결 방향 속에서 브랜드/서비스/상품이 자연스럽게 남게 한다
- 읽고 나면 "그냥 넘기면 안 되겠구나" 또는 "한 번 더 점검해봐야겠구나"가 남아야 한다
`
};

const roleGuide = roleGuideMap[postRole] ?? roleGuideMap.promo;

//------------------------------------------------
// length profile
//------------------------------------------------
const lengthProfiles = {
  summary: {
    modeLabel: "요약형",
    targetChars: 900,
    minChars: 750,
    maxChars: 1050,
    minH2: 4,
    maxH2: 5
  },
  explain: {
    modeLabel: "설명형",
    targetChars: 1200,
    minChars: 1000,
    maxChars: 1450,
    minH2: 5,
    maxH2: 6
  },
  expert: {
    modeLabel: "전문가형",
    targetChars: 1550,
    minChars: 1350,
    maxChars: 1850,
    minH2: 6,
    maxH2: 7
  }
};

const lengthProfile = lengthProfiles[mode] ?? lengthProfiles.summary;

//------------------------------------------------
// context
//------------------------------------------------
const contextFull = {
  topicAnchor: {
    brandName: norm(ctx.brand_name),
    keywordDisplay: mainKeyword,
    regionHint: norm(ctx.address),
    industry: norm(ctx.industry),
    productName: norm(ctx.product_name),
    serviceTypes: norm(ctx.service_types),
    inquiryChannels: norm(ctx.inquiry_channels)
  },
  brandAssets: {
    goal: norm(ctx.goal),
    tones: norm(ctx.tones),
    actionStyle: norm(ctx.action_style),
    expression: norm(ctx.expression),
    forbiddenPhrases: norm(ctx.forbidden_phrases),
    productStrengths: norm(ctx.product_strengths),
    extraStrength: norm(ctx.extra_strength),
    extraTokens: safeArr(ctx.extraTokens)
  },
  keywordPack: {
    selectedKeywords,
    keywordCandidates3,
    keywordCandidates10
  },
  roleGuide: {
    postRole,
    roleGuideText: roleGuide
  },
  lengthProfile
};

//------------------------------------------------
// system prompt
//------------------------------------------------
const SYSTEM_PROMPT = `
너는 전문 블로그 콘텐츠 작성자다.

반드시 지킬 규칙
- 입력 컨텍스트 밖의 정보 생성 금지
- 허위 수치 생성 금지
- 업종 변경 금지
- 과장 광고 금지
- Markdown 본문은 반드시 "## " H2만 사용
- 교과서식 서론 금지
- 일반론만 반복하는 문단 금지
- 각 H2는 실제 검색자가 판단에 써먹을 수 있는 기준, 실수, 비교 포인트, 확인 질문 중 최소 1개를 포함해야 한다
- 짧은 문장과 설명 문장을 자연스럽게 섞는다
- 모든 문장을 반듯한 안내문처럼 정리하지 않는다
- 사례가 입력에 없으면 구체 사례를 꾸며내지 않는다
- 숫자가 입력에 없으면 숫자를 꾸며내지 않는다
- 참고 자료가 제공된 경우 그 내용을 적극 활용해 깊이 있는 글을 써라
- 참고 자료에 없는 수치·법령·판례·구체 사례는 절대 만들어내지 말 것
`;

//------------------------------------------------
// user prompt
//------------------------------------------------
const USER_PROMPT = `
블로그 글을 작성하라.

[글 모드]
${lengthProfile.modeLabel}

[글자수 목표]
${lengthProfile.targetChars}자 내외
허용 범위: ${lengthProfile.minChars} ~ ${lengthProfile.maxChars}

[H2 개수]
${lengthProfile.minH2} ~ ${lengthProfile.maxH2}개

[핵심 작성 원칙]
- 실제 검색자가 왜 이 키워드를 검색했는지 드러나야 한다
- 정의 설명으로만 밀지 말고, 실제로 어디서 막히는지 써야 한다
- 각 섹션은 최소 1개 이상 아래 요소 중 하나를 포함한다
  1. 실제로 많이 막히는 지점
  2. 실수하기 쉬운 부분
  3. 비교 기준
  4. 선택 전에 확인할 질문
  5. 진행 전에 먼저 볼 조건
- 글 전체에 표는 최소 1개 포함한다
- 글 전체에 짧은 문장/짧은 문단이 일부 자연스럽게 섞여야 한다
- 단, 억지로 모든 섹션을 짧게 만들지는 않는다
- 이모지는 꼭 필요할 때만 제한적으로 사용한다
- 이모지는 문장 맨 앞만 허용하고, H2/summary/리스트에는 넣지 않는다
- 브랜드는 독립 소개 문단처럼 넣지 말고, 판단 기준/확인 포인트/차이 설명/이용 맥락 안에만 자연스럽게 배치한다
- 정보 + 흥미 + 브랜드/서비스/상품 자연 반영이 함께 있어야 한다
- 읽고 나서 판단에 도움이 되어야 하고, 동시에 한 번 더 확인하거나 비교해볼 필요성도 자연스럽게 남아야 한다

[role]
현재 role: ${postRole}

${roleGuide}

[제목 규칙]
- title에는 반드시 메인 키워드 "${mainKeyword}" 를 포함한다
- 제목은 한국 블로그에서 볼 법한 자연스러운 문장형으로 쓴다
- "~의 중요성", "~완벽 가이드", "~총정리" 같은 표현 금지
- 너무 교과서형 제목 금지

[출력 규칙]
반드시 JSON

필드
title
summary
bodyMarkdown
cta
hashtags
selectedKeywords

[추가 규칙]
- summary는 2문장 이내
- summary는 정보만 요약하고 끝내지 말고, 검색자가 왜 봐야 하는지가 자연스럽게 드러나야 한다
- bodyMarkdown은 반드시 "## " 제목만 사용
- bodyMarkdown 안에는 최소 1개의 Markdown 표 포함
- selectedKeywords에는 반드시 ${JSON.stringify(selectedKeywords)} 반영
- cta.text는 글 주제와 자연스럽게 이어지는 문장으로 작성한다

컨텍스트
${inJson.rag_context ? "[참고 자료 — Perplexity 검색 결과, 사실 기반 작성에 활용]\n" + inJson.rag_context + "\n\n" : ""}${JSON.stringify(contextFull, null, 2)}
`;

//------------------------------------------------
// schema
//------------------------------------------------
const schema = {
  type: "object",
  properties: {
    title: { type: "string" },
    summary: { type: "string" },
    bodyMarkdown: { type: "string" },
    cta: {
      type: "object",
      properties: {
        text: { type: "string" },
        urlOrContact: { type: "string" }
      },
      required: ["text", "urlOrContact"],
      additionalProperties: false
    },
    hashtags: {
      type: "array",
      items: { type: "string" }
    },
    selectedKeywords: {
      type: "array",
      items: { type: "string" }
    }
  },
  required: [
    "title",
    "summary",
    "bodyMarkdown",
    "cta",
    "hashtags",
    "selectedKeywords"
  ],
  additionalProperties: false
};

//------------------------------------------------
// payload
//------------------------------------------------
return [
  {
    json: {
      model: "gpt-5-3",
      input: [
        { role: "system", content: SYSTEM_PROMPT },
        { role: "user", content: USER_PROMPT }
      ],
      text: {
        format: {
          type: "json_schema",
          name: "blog_post",
          schema,
          strict: true
        }
      },
      _meta: {
        postRole,
        mode,
        selectedKeywords,
        brandName: norm(ctx.brand_name),
        extraStrength: norm(ctx.extra_strength),
        industry: norm(ctx.industry),
        toneGuide: norm(ctx.tones),
        actionStyle: norm(ctx.action_style),
        expression: norm(ctx.expression)
      }
    }
  }
];

function safeItems(nodeName) {
  try {
