/**
 * Node name: NAVER_SE_HTML_BUILDER_V3 (PATCH: LABEL_EMOJI + AUTO_BOLD + NUMBER_HIGHLIGHT + EMOJI_BUDGET + MD_TABLE_RENDER
 * + ✅ LIST_SAFE_EMOJI + ✅ KO_BOLD_FIX + ✅ STAR_LIST_FIX + ✅ EMOJI_LIST_JOIN + ✅ KO_SENT_SPLIT
 * + ✅ COMPACT_LINES (일반문장 1줄, 이모지 접두는 2줄) )
 * Node type: Code
 * Mode: Run Once for Each Item (For Each Item)
 */

function norm(x){
  return String(x ?? "")
    .replace(/\r\n/g,"\n")
    .replace(/\r/g,"\n")
    .trim();
}

function esc(str){
  return String(str ?? "")
    .replace(/&/g,"&amp;")
    .replace(/</g,"&lt;")
    .replace(/>/g,"&gt;")
    .replace(/"/g,"&quot;");
}

// **텍스트** → <strong>텍스트</strong>
function applyMarkdownBold(text){
  return String(text ?? "").replace(/\*\*(.*?)\*\*/g, "<strong>$1</strong>");
}

// ### 타이틀: -> 굵게 라벨 처리
function transformH3Colon(text){
  return String(text ?? "")
    .replace(/^###\s*([^:]+):\s*/gm, function(_, title){
      return `\n\n<strong>${title}:</strong> `;
    });
}

function autoLink(text){
  return String(text ?? "")
    .replace(/(https?:\/\/[^\s]+)/g, function(url){
      const u = String(url);
      return `<a href="${u}" target="_blank" rel="noopener noreferrer">${u}</a>`;
    });
}

function autoLinebreakMarkers(text){
  let t = String(text ?? "");

  // 1) 이모지 라벨 앞은 줄바꿈
  t = t.replace(/([^\n])\s*(✅|☑️|✔️|📌|⚠️|❗|💡|🧾|❓|💰|🕒|📍)\s+/g, "$1\n$2 ");

  return t;
}

/**
 * 허용 태그만 복구:
 * - <strong>, </strong>, <a ...>, </a> 만 복구
 */
function restoreAllowedTags(escapedHtml){
  let t = String(escapedHtml ?? "");

  t = t.replace(/&lt;strong&gt;/g, "<strong>")
       .replace(/&lt;\/strong&gt;/g, "</strong>");

  t = t.replace(/&lt;\/a&gt;/g, "</a>");

  t = t.replace(/&lt;a\b([^&]*)&gt;/g, (m, attrs) => {
    const candidate = `<a${attrs}>`;
    const hasHref =
      /href=&quot;https?:\/\/[^&]+&quot;/i.test(candidate) ||
      /href="https?:\/\/[^"]+"/i.test(candidate);

    if (!hasHref) return m;

    return candidate.replace(/&quot;/g, '"').replace(/&amp;/g, "&");
  });

  return t;
}

