/* -------------------- ✅ 리스트 판별(중요) -------------------- */
function isListLine(line){
  const s = String(line ?? "").trim();
  return /^(\*|-|·)\s+/.test(s) || /^\d+\s*[\.\)]\s+/.test(s);
}

/* -------------------- ✅ 가독성/불릿 정규화 -------------------- */

const EMOJIS = ["⚠️","📌","✅","☑️","❗","💡","🧾","❓","💰","🕒","📍"];
const EMOJI_RE = new RegExp(`^(${EMOJIS.map(e=>e.replace(/[.*+?^${}()|[\]\\]/g,"\\$&")).join("|")})\\s+`);

function getLeadingEmojiPrefix(line){
  const m = String(line ?? "").match(EMOJI_RE);
  return m ? m[1] : "";
}
function stripLeadingEmojiPrefix(line){
  return String(line ?? "").replace(EMOJI_RE, "");
}

function normalizeStarBullet(line){
  let s = String(line ?? "").trim();
  if (!s) return s;

  s = s.replace(EMOJI_RE, (m) => m.trim() + " ");
  s = s.replace(new RegExp(`^(${EMOJIS.map(e=>e.replace(/[.*+?^${}()|[\]\\]/g,"\\$&")).join("|")})\\s*\\*\\s+`), "$1 · ");
  s = s.replace(/^\*\s+/, "· ");

  return s;
}

/* -------------------- ✅ 라벨 이모지 + 자동 굵게 -------------------- */

const LABEL_RULES = [
  { re: /^(주의|경고|위험|금지)\s*[:：-]\s*/i, emoji: "⚠️" },
  { re: /^(필수|중요|핵심|우선)\s*[:：-]\s*/i, emoji: "✅" },
  { re: /^(체크|체크포인트|점검)\s*[:：-]\s*/i, emoji: "✅" },
  { re: /^(팁|TIP|꿀팁)\s*[:：-]\s*/i, emoji: "💡" },
  { re: /^(정리|요약|결론)\s*[:：-]\s*/i, emoji: "🧾" },
  { re: /^(FAQ|자주\s*묻는\s*질문)\s*[:：-]\s*/i, emoji: "❓" },
  { re: /^(문의|상담|예약|안내)\s*[:：-]\s*/i, emoji: "📌" },
  { re: /^(비용|가격)\s*[:：-]\s*/i, emoji: "💰" },
  { re: /^(시간|소요시간|운영시간)\s*[:：-]\s*/i, emoji: "🕒" },
  { re: /^(주소|위치|오시는\s*길)\s*[:：-]\s*/i, emoji: "📍" },
];

const BOLD_KEYWORDS = [
  "반드시","권장","추천","주의","중요","핵심","필수","우선","금지","불가","가능","필요",
  "확인","점검","준비","정리","기준","원인","방법","대안","예외","주의사항",
  "누락","가산세","증빙","기한","절차","체크리스트"
];

function escapeRegex(s){ return s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&"); }

function wrapKeywordSafe(text, kw){
  const w = escapeRegex(kw);
  const re = new RegExp(`(^|[^가-힣A-Za-z0-9])(${w})(?=[^가-힣A-Za-z0-9]|$)`, "g");
  return String(text ?? "").replace(re, (m, p1, p2) => `${p1}<strong>${p2}</strong>`);
}

function boldKeywords(line){
  let t = String(line ?? "");
  for (const w of BOLD_KEYWORDS){
    if (t.includes(`<strong>${w}</strong>`)) continue;
    t = wrapKeywordSafe(t, w);
  }
  return t;
}

function boldNumbersAndUnits(line){
  let t = String(line ?? "");

  t = t.replace(/(\d+)\s*(~|-)\s*(\d+)\s*(회|번|일|주|개월|달|분|초|시간|%|퍼센트)?/g, (m)=>{
    return `<strong>${m}</strong>`;
  });

  t = t.replace(/(\d+(?:\.\d+)?)\s*(회|번|일|주|개월|달|분|초|시간|%|퍼센트|kg|g|cm|mm)\b/g, (m)=>{
    return `<strong>${m}</strong>`;
  });

  return t;
}

function boldListLabel(line){
  let s = String(line ?? "").trim();

  s = s.replace(/^(\d+\s*[\.\)]\s*)([^:：]{2,30})(\s*[:：]\s*)/,
    (m, pfx, label, colon) => `${pfx}<strong>${label}</strong>${colon}`
  );

  s = s.replace(/^(\*|-|·)\s*([^:：]{2,30})(\s*[:：]\s*)/,
    (m, bullet, label, colon) => `${bullet} <strong>${label}</strong>${colon}`
  );

  return s;
}

function boldShortConclusionLike(line){
  const raw = String(line ?? "").trim();
  const plain = raw.replace(/<[^>]+>/g, "");
  if (plain.length <= 48 && /^(🧾|요약|결론|정리)\b|요약하면|결론적으로/.test(plain)) {
    if (!/^<strong>/.test(raw)) return `<strong>${raw}</strong>`;
  }
  return raw;
}

function applyLabelEmoji(line){
  let t = String(line ?? "").trim();
  if (!t) return t;
  if (getLeadingEmojiPrefix(t)) return t;

  for (const r of LABEL_RULES){
    if (r.re.test(t)){
      t = t.replace(r.re, "");
      t = `${r.emoji} ${t}`;
      return t;
    }
  }
  return t;
}

function enhanceLine(line){
  let t = String(line ?? "").trim();
  if (!t) return t;

  t = normalizeStarBullet(t);

  const list = isListLine(stripLeadingEmojiPrefix(t));

  if (!list) t = applyLabelEmoji(t);

  if (list) t = boldListLabel(t);

  t = boldNumbersAndUnits(t);
  t = boldKeywords(t);
  t = boldShortConclusionLike(t);

  return t;
}

/* -------------------- ✅ 줄 분절 -------------------- */

function isEmojiOnlyLine(line){
  const s = String(line ?? "").trim();
  return EMOJIS.includes(s);
}

function isEmojiPrefixLine(line){
  return !!getLeadingEmojiPrefix(String(line ?? "").trim());
}

function compactLines(lines){
  const arr = (Array.isArray(lines) ? lines : [])
    .map(s => String(s ?? "").trim())
    .filter(Boolean);

  const out = [];
  let i = 0;

  while (i < arr.length) {
    const cur = arr[i];
    const curNoEmoji = stripLeadingEmojiPrefix(cur);

    if (isListLine(curNoEmoji)) {
      out.push(cur);
      i++;
      continue;
    }

    if (isEmojiPrefixLine(cur)) {
      out.push(cur);
      const next = arr[i + 1];
      if (next) {
        const nextNoEmoji = stripLeadingEmojiPrefix(next);
        const nextIsList = isListLine(nextNoEmoji);
        const nextIsEmoji = isEmojiPrefixLine(next);
        if (!nextIsList && !nextIsEmoji) {
          out.push(next);
          i += 2;
          continue;
        }
      }
      i++;
      continue;
    }

    let merged = cur;
    while (true) {
      const next = arr[i + 1];
      if (!next) break;

      const nextNoEmoji = stripLeadingEmojiPrefix(next);
      if (isEmojiPrefixLine(next)) break;
      if (isListLine(nextNoEmoji)) break;
      if ((merged + " " + next).length > 120) break;

      merged = merged + " " + next;
      i++;
    }

    out.push(merged);
    i++;
  }

  return out;
}

function rhythmLines(text){
  const t = norm(autoLinebreakMarkers(transformH3Colon(text)));
  if (!t) return [];

  const rawLines0 = t.split(/\n+/).map(x => x.trim()).filter(Boolean);

  const rawLines = [];
  for (let i=0;i<rawLines0.length;i++){
    const cur = rawLines0[i];
    const next = rawLines0[i+1];

    if (isEmojiOnlyLine(cur) && next && isListLine(next)) {
      rawLines.push(`${cur} ${next}`);
      i++;
      continue;
    }
    rawLines.push(cur);
  }

  const out = [];
  for (const ln of rawLines){
    const withLinks = autoLink(ln);
    const one = norm(withLinks);

    if (one.length <= 90) {
      out.push(one);
      continue;
    }

    let sents = one
      .split(/(?<=[\.!\?…]|다\.|니다\.|습니다\.|요\.|죠\.|까요\.|합니다\.)\s+/)
      .map(x => x.trim())
      .filter(Boolean);

    if (sents.length <= 1 && one.length > 90) {
      const sents2 = one
        .split(/(?<=(다|니다|습니다|요|죠|까요|합니다))\s+/)
        .map(x => x.trim())
        .filter(Boolean);
      if (sents2.length > 1) sents = sents2;
    }

    if (sents.length <= 1) {
      out.push(one);
      continue;
    }

    let buf = "";
    for (const s of sents){
      const next = buf ? (buf + " " + s) : s;
      if (next.length > 140 && buf) {
        out.push(buf.trim());
        buf = s;
      } else {
        buf = next;
      }
    }
    if (buf) out.push(buf.trim());
  }

  return out;
}

/* -------------------- ✅ EMOJI BUDGET -------------------- */

function stripHtmlTags(s){
  return String(s ?? "").replace(/<[^>]*>/g, " ").replace(/\s+/g, " ").trim();
}

function calcBudgetFromText(text){
  const one = stripHtmlTags(text);
  const len = one.length;
  if (len <= 180) return 1;
  if (len <= 520) return 2;
  return 3;
}

function scoreLine(line){
  const raw = String(line ?? "").trim();
  const rawNoEmoji = stripLeadingEmojiPrefix(raw);
  if (isListLine(rawNoEmoji)) return -999;

  const s = stripHtmlTags(raw);
  let sc = 0;

  if (/(위험|악화|통증|피|호흡|경련|쇼크|즉시|경고|금지|하면\s*안)/.test(s)) sc += 280;
  if (/(확인|점검|기준|방법|팁|체크|정리|순서|준비|포인트|핵심|FAQ|Q\.|A\.)/.test(s)) sc += 140;
  if (/(문의|비용|가격|가능)/.test(s)) sc += 60;

  if (s.length <= 14) sc -= 40;
  return sc;
}

function pickPrefixByScore(sc){
  if (sc >= 260) return "⚠️";
  if (sc >= 130) return "📌";
  return "✅";
}

function applyEmojiBudget(lines, budgetCap){
  const arr = (Array.isArray(lines) ? lines : []).map(x => String(x ?? "").trim()).filter(Boolean);
  if (!arr.length) return arr;

  const cap = Math.max(0, Number(budgetCap || 0));
  if (cap <= 0) {
    return arr.map(l => stripLeadingEmojiPrefix(l));
  }

  const emojiIdx = [];
  for (let i=0;i<arr.length;i++){
    const raw = arr[i];
    const rawNoEmoji = stripLeadingEmojiPrefix(raw);
    if (isListLine(rawNoEmoji)) continue;
    if (getLeadingEmojiPrefix(raw)) emojiIdx.push(i);
  }

  if (emojiIdx.length > cap) {
    const keep = new Set(emojiIdx.slice(0, cap));
    for (let i=0;i<arr.length;i++){
      const rawNoEmoji = stripLeadingEmojiPrefix(arr[i]);
      if (isListLine(rawNoEmoji)) continue;
      if (!keep.has(i) && getLeadingEmojiPrefix(arr[i])) arr[i] = stripLeadingEmojiPrefix(arr[i]);
    }
  }

  let used = 0;
  for (const l of arr){
    const rawNoEmoji = stripLeadingEmojiPrefix(l);
    if (isListLine(rawNoEmoji)) continue;
    if (getLeadingEmojiPrefix(l)) used++;
  }
  let remain = cap - used;
  if (remain <= 0) return arr;

  const cand = [];
  for (let i=0;i<arr.length;i++){
    const raw = arr[i];
    const rawNoEmoji = stripLeadingEmojiPrefix(raw);
    if (isListLine(rawNoEmoji)) continue;
    if (getLeadingEmojiPrefix(raw)) continue;

    const sc = scoreLine(raw);
    if (sc > 0) cand.push({i, sc});
  }

  cand.sort((a,b)=>(b.sc-a.sc)||(a.i-b.i));

  for (const c of cand){
    if (remain <= 0) break;

    const prevHas = (c.i-1>=0) ? !!getLeadingEmojiPrefix(arr[c.i-1]) : false;
    const nextHas = (c.i+1<arr.length) ? !!getLeadingEmojiPrefix(arr[c.i+1]) : false;
    if (prevHas || nextHas) continue;

    arr[c.i] = `${pickPrefixByScore(c.sc)} ${arr[c.i]}`;
    remain--;
  }

  return arr;
}

/* -------------------- ✅ Markdown table render -------------------- */

function isMdTableSepLine(line){
  const s = String(line ?? "").trim();
  return /^\|?\s*:?-{3,}:?\s*(\|\s*:?-{3,}:?\s*)+\|?\s*$/.test(s);
}
function isMdTableRowLine(line){
  const s = String(line ?? "");
  return /\|/.test(s);
}
function splitMdTableRow(line){
  let s = String(line ?? "").trim();
  if (s.startsWith("|")) s = s.slice(1);
  if (s.endsWith("|")) s = s.slice(0, -1);
  return s.split("|").map(c => c.trim());
}
function parseMdTable(blockLines){
  const header = splitMdTableRow(blockLines[0]);
  const sep = blockLines[1];

  const aligns = splitMdTableRow(sep).map(cell=>{
    const t = cell.replace(/\s+/g,"");
    const left = t.startsWith(":");
    const right = t.endsWith(":");
    if (left && right) return "center";
    if (right) return "right";
    return "left";
  });

  const rows = blockLines.slice(2).map(splitMdTableRow);
  return { header, aligns, rows };
}

function splitBodyIntoBlocks(md){
  const lines = norm(md).split("\n");
  const blocks = [];
  let buf = [];

  function flushText(){
    const t = buf.join("\n").trim();
    if (t) blocks.push({ type:"text", text:t });
    buf = [];
  }

  for (let i=0;i<lines.length;i++){
    const line = lines[i];

    if (isMdTableRowLine(line) && i+1 < lines.length && isMdTableSepLine(lines[i+1])) {
      flushText();
      const tbl = [line, lines[i+1]];
      i += 2;

      while (i < lines.length && lines[i].trim() !== "" && isMdTableRowLine(lines[i])) {
        tbl.push(lines[i]);
        i++;
      }
      i--;

      blocks.push({ type:"table", lines: tbl });
      continue;
    }

    buf.push(line);
  }

  flushText();
  return blocks;
}

function tableBlockFromMd(mdLines){
  const t = parseMdTable(mdLines);

  function renderCell(raw, align){
    let v = raw;
    v = autoLink(v);
    v = applyMarkdownBold(v);
    v = enhanceLine(v);

    const escaped = esc(v);
    const safe = restoreAllowedTags(escaped);

    const style =
      align === "center" ? "text-align:center;" :
      align === "right"  ? "text-align:right;"  :
                           "text-align:left;";

    return { safe, style };
  }

  const thead = t.header.map((h, idx)=>{
    const { safe, style } = renderCell(h, t.aligns[idx] || "left");
    return `<th style="${style} padding:10px; border:1px solid #e5e5e5; background:#fafafa;">${safe}</th>`;
  }).join("");

  const tbody = t.rows.map(r=>{
    const tds = r.map((cell, idx)=>{
      const { safe, style } = renderCell(cell, t.aligns[idx] || "left");
      return `<td style="${style} padding:10px; border:1px solid #e5e5e5;">${safe}</td>`;
    }).join("");
    return `<tr>${tds}</tr>`;
  }).join("");

  return `
<div class="se-component se-table se-l-default">
  <div class="se-component-content">
    <div class="se-section se-section-table se-l-default">
      <div class="se-module se-module-table">
        <table class="se-table-content" style="width:100%; border-collapse:collapse;">
          <thead><tr>${thead}</tr></thead>
          <tbody>${tbody}</tbody>
        </table>
      </div>
    </div>
  </div>
</div>`.trim();
}

/* -------------------- Markdown(##) → sections -------------------- */

function parseSections(md){
  const parts = String(md ?? "").split(/^## /gm).filter(Boolean);

  return parts.map((p, idx)=>{
    const lines = p.split("\n");

    const firstLine = (lines[0] || "").trim();

    const isRealH2 =
      idx !== 0 ||
      /^.{1,40}$/.test(firstLine) && !/[.!?]$/.test(firstLine);

    if (!isRealH2) {
      return {
        h2: "",
        body: p.trim()
      };
    }

    const h2 = lines.shift().trim();
    const body = lines.join("\n").trim();

    return { h2, body };
  });
}

