/**
 * Node name: FINAL_REVIEW_OUTPUT_ADAPTER
 * Node type: Code (n8n-nodes-base.code)
 * Mode: Run Once for All Items
 *
 * 입력 데이터 구조 가정:
 * 1) [{ json: { output: "```json\n{...}\n```" } }, ...]
 * 2) [{ json: { content: { parts: [{ text: "```json\n{...}\n```" }] } } }, ...]
 * 3) [{ json: { candidates: [{ content: { parts: [{ text: "```json\n{...}\n```" }] } }] } }, ...]
 *
 * 출력 데이터 구조:
 * [
 *   {
 *     json: {
 *       ok: true,
 *       title: string,
 *       summary: string,
 *       sections: [
 *         {
 *           h2: string,
 *           bodyMarkdown: string
 *         }
 *       ],
 *       rawParsed: object
 *     }
 *   }
 * ]
 */

function stripCodeFences(s) {
  s = String(s ?? "").trim();
  s = s.replace(/^```(?:json)?\s*\n?/i, "");
  s = s.replace(/\n?```\s*$/i, "");
  return s.trim();
}

function safeJsonParse(str) {
  try {
    return JSON.parse(str);
  } catch {
    return null;
  }
}

function splitByH2(bodyMarkdown) {
  const text = String(bodyMarkdown ?? "").replace(/\r\n/g, "\n").trim();
  if (!text) return [];

  const parts = text.split(/\n(?=##\s+)/g);
  const sections = [];

  for (const part of parts) {
    const chunk = part.trim();
    if (!chunk) continue;

    const m = chunk.match(/^##\s+(.+?)\n([\s\S]*)$/);
    if (m) {
      sections.push({
        h2: (m[1] ?? "").trim(),
        bodyMarkdown: (m[2] ?? "").trim(),
      });
    } else {
      sections.push({
        h2: "",
        bodyMarkdown: chunk,
      });
    }
  }

  return sections;
}

function extractTextFromParts(parts) {
  if (!Array.isArray(parts)) return "";
  return parts
    .map((p) => {
      if (typeof p === "string") return p;
      if (p && typeof p === "object" && typeof p.text === "string") return p.text;
      return "";
    })
    .filter(Boolean)
    .join("\n")
    .trim();
}

function extractRawText(json) {
  // 1) 기존 output 구조
  if (typeof json?.output === "string" && json.output.trim()) {
    return json.output.trim();
  }

  // 2) content.parts[].text 구조
  const fromContentParts = extractTextFromParts(json?.content?.parts);
  if (fromContentParts) return fromContentParts;

  // 3) candidates[].content.parts[].text 구조
  if (Array.isArray(json?.candidates)) {
    for (const candidate of json.candidates) {
      const text = extractTextFromParts(candidate?.content?.parts);
      if (text) return text;
    }
  }

  return "";
}

const items = $input.all();

return items.map((it, index) => {
  const raw = extractRawText(it.json ?? {});
  const jsonText = stripCodeFences(raw);
  const parsed = safeJsonParse(jsonText);

  if (!raw) {
    return {
      json: {
        ok: false,
        error: "No supported text path found. Expected output or content.parts[].text or candidates[].content.parts[].text",
        itemIndex: index,
        inputPreview: JSON.stringify(it.json ?? {}).slice(0, 1500),
      },
    };
  }

  if (!parsed) {
    return {
      json: {
        ok: false,
        error: "JSON parse failed. Check if output string is valid JSON inside code fences.",
        itemIndex: index,
        raw,
        stripped: jsonText,
      },
    };
  }

  const title = parsed.title ?? "";
  const summary = parsed.summary ?? "";
  const bodyMarkdown = parsed.bodyMarkdown ?? "";
  const sections = splitByH2(bodyMarkdown);

