      ok: true,
      title,
      summary,
      sections,
      rawParsed: parsed,
    },
  };
});

function normalizeBody(text) {
  let t = String(text ?? "").replace(/\r\n/g, "\n");

  if (!t.trim()) return "";

  // 과도한 빈 줄 정리
  t = t.replace(/\n{3,}/g, "\n\n");

  // 문단 단위 정리
  const paragraphs = t.split("\n\n").map(p => p.trim()).filter(Boolean);

  const leadWords = ["또한", "그리고", "하지만", "다만", "즉", "특히", "이 경우", "이때"];
  let prevLead = "";

  const cleaned = paragraphs.map((p) => {
    let out = p;

    // 같은 연결어가 연속 문단에서 반복되면 뒤 문단 것은 제거
    for (const word of leadWords) {
      const re = new RegExp(`^${word}[, ]*`);
      if (re.test(out)) {
        if (prevLead === word) {
          out = out.replace(re, "");
        }
        prevLead = word;
        return out.trim();
      }
    }

    prevLead = "";
    return out.trim();
  });

  t = cleaned.join("\n\n");

  // 표 앞뒤 줄바꿈 안정화
  t = t.replace(/\n{3,}\|/g, "\n\n|");
  t = t.replace(/\|\n{3,}/g, "|\n\n");

  // 리스트 앞뒤 과도한 공백 제거
  t = t.replace(/\n{3,}\*/g, "\n\n*");
  t = t.replace(/\n{3,}\d+\./g, "\n\n$&".replace("\n\n\n", "\n\n"));

  return t.trim();
}

